mapper.select:
/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.selectAccountList */ SELECT m.user_no /** 사용자번호 */ , m.user_id /** 사용자아이디 */ , m.user_nm /** 사용자명 */ , m.user_telno /** 사용자전화번호 */ , m.user_eml /** 사용자이메일 */ , m.user_yn /** 사용자사용여부 */ , m.reg_dt /** 등록일자 */ , m.mdf_dt /** 수정일자 */ , g.mgmt_ofc_no /** 관리사무소번호 */ , g.mngr_duty_cd /** 관리자직무코드 */ , o.apt_cmplex_no /** 단지번호 */ , a.apt_cmplex_nm /** 단지명 */ , a.sido_nm /** 시도명 */ , a.sigungu_nm /** 시군구명 */ , a.emd_nm /** 읍면동명 */ , TRIM( NVL(a.sido_nm, '') || ' ' || NVL(a.sigungu_nm, '') || ' ' || NVL(a.emd_nm, '') ) AS detail_addr /** 상세주소 */ , CASE g.mngr_duty_cd WHEN 'DUTY_HEAD' THEN '관리소장' WHEN 'DUTY_ACC' THEN '회계' WHEN 'DUTY_ADMIN' THEN '행정' WHEN 'DUTY_FAC' THEN '시설' WHEN 'HEAD' THEN '관리소장' WHEN 'ACNT' THEN '회계' WHEN 'ADM' THEN '행정' WHEN 'FAC' THEN '시설' ELSE g.mngr_duty_cd END AS duty_nm /** 직무명 */ , TO_CHAR(NVL(m.mdf_dt, m.reg_dt), 'YYYY-MM-DD') AS last_login_dt /** 최근로그인일자 */ , TO_CHAR(NVL(m.mdf_dt, m.reg_dt), 'HH24:MI') AS last_login_tm /** 최근로그인시각 */ FROM member m LEFT JOIN auth au ON m.user_no = au.user_no LEFT JOIN manager g ON m.user_no = g.user_no LEFT JOIN mgmt_office o ON g.mgmt_ofc_no = o.mgmt_ofc_no LEFT JOIN apt_complex a ON o.apt_cmplex_no = a.apt_cmplex_no WHERE 1 = 1 AND au.user_role_cd = 'ROLE_MNGR' AND g.user_no IS NOT NULL
AND ( LOWER(m.user_nm) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(m.user_id) LIKE '%' || LOWER(#{keyword}) || '%' OR LOWER(a.apt_cmplex_nm) LIKE '%' || LOWER(#{keyword}) || '%' )
AND m.user_yn = 'Y'
AND m.user_yn = 'N'
AND g.mngr_duty_cd = #{role}
ORDER BY m.reg_dt DESC , m.user_no DESC

/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.countMemberByUserId */
SELECT
COUNT(*)                                                     AS cnt              /** 회원아이디건수 */
FROM member m
WHERE 1 = 1
AND m.user_id = #{userId}

mapper.update:
/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.updateAuthToManager */
UPDATE auth au
SET
au.user_role_cd = 'ROLE_MNGR'         /** 사용자권한코드 */
WHERE 1 = 1
AND au.user_no = #{userNo}

mapper.select:
/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.countManagerByUserNo */
SELECT
COUNT(*)                              AS cnt              /** 관리자건수 */
FROM manager g
WHERE 1 = 1
AND g.user_no = #{userNo}

mapper.update:
/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.updateAccountDsplyYn */
UPDATE mngr_rqst r
SET
r.acnt_dsply_yn = 'N'                 /** 계정화면표시여부 */
WHERE 1 = 1
AND r.rqst_no = #{rqstNo}

mapper.select:
/* kr.or.ddit.domain.central.admin.mapper.IMngrRqstAprvMapper.selectUserNoByLoginId */
SELECT
m.user_no                              /** 사용자번호 */
FROM member m
WHERE 1 = 1
AND m.user_id = #{rqstLoginId}
